package com.example.network.repository

import com.example.network.NetworkClient
import com.example.network.model.UserProfile
import com.example.network.result.NetworkResult
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import retrofit2.Response

class UserRepository(
    private val apiService = NetworkClient.userApiService
) {

    suspend fun getUsers(page: Int = 1, perPage: Int = 20): NetworkResult<List<UserProfile>> {
        return safeApiCall {
            val response = apiService.getUsers(page, perPage)
            if (response.isSuccessful) {
                val body = response.body()
                if (body != null) {
                    NetworkResult.Success(body.data)
                } else {
                    NetworkResult.Error(response.code(), "Empty response body")
                }
            } else {
                NetworkResult.Error(response.code(), response.errorBody()?.string())
            }
        }
    }

    suspend fun getUserById(userId: Long): NetworkResult<UserProfile> {
        return safeApiCall {
            val response = apiService.getUserById(userId)
            if (response.isSuccessful) {
                val body = response.body()?.data
                if (body != null) {
                    NetworkResult.Success(body)
                } else {
                    NetworkResult.Error(response.code(), "User not found")
                }
            } else {
                NetworkResult.Error(response.code(), response.errorBody()?.string())
            }
        }
    }

    suspend fun getCurrentUser(): NetworkResult<UserProfile> {
        return safeApiCall {
            val response = apiService.getCurrentUser()
            if (response.isSuccessful) {
                val body = response.body()?.data
                if (body != null) {
                    NetworkResult.Success(body)
                } else {
                    NetworkResult.Error(response.code(), "User data unavailable")
                }
            } else {
                NetworkResult.Error(response.code(), response.errorBody()?.string())
            }
        }
    }

    suspend fun updateCurrentUser(updates: Map<String, String>): NetworkResult<UserProfile> {
        return safeApiCall {
            val response = apiService.updateCurrentUser(updates)
            if (response.isSuccessful) {
                val body = response.body()?.data
                if (body != null) {
                    NetworkResult.Success(body)
                } else {
                    NetworkResult.Error(response.code(), "Update failed")
                }
            } else {
                NetworkResult.Error(response.code(), response.errorBody()?.string())
            }
        }
    }

    suspend fun searchUsers(query: String, page: Int = 1): NetworkResult<List<UserProfile>> {
        return safeApiCall {
            val response = apiService.searchUsers(query, page)
            if (response.isSuccessful) {
                val body = response.body()
                if (body != null) {
                    NetworkResult.Success(body.data)
                } else {
                    NetworkResult.Error(response.code(), "Empty response body")
                }
            } else {
                NetworkResult.Error(response.code(), response.errorBody()?.string())
            }
        }
    }

    private suspend fun <T> safeApiCall(
        apiCall: suspend () -> NetworkResult<T>
    ): NetworkResult<T> {
        return withContext(Dispatchers.IO) {
            try {
                apiCall()
            } catch (e: Exception) {
                NetworkResult.Exception(e)
            }
        }
    }
}

