package com.example.app.ui

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.network.NetworkModule
import com.example.network.model.UserProfile
import com.example.network.result.NetworkResult
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

data class UserUiState(
    val isLoading: Boolean = false,
    val users: List<UserProfile> = emptyList(),
    val currentUser: UserProfile? = null,
    val errorMessage: String? = null
)

class UserViewModel : ViewModel() {

    private val userRepository = NetworkModule.userRepository

    private val _uiState = MutableStateFlow(UserUiState())
    val uiState: StateFlow<UserUiState> = _uiState.asStateFlow()

    fun fetchUsers(page: Int = 1) {
        viewModelScope.launch {
            _uiState.value = _uiState.value.copy(isLoading = true, errorMessage = null)

            when (val result = userRepository.getUsers(page)) {
                is NetworkResult.Success -> {
                    _uiState.value = _uiState.value.copy(
                        isLoading = false,
                        users = result.data
                    )
                }
                is NetworkResult.Error -> {
                    _uiState.value = _uiState.value.copy(
                        isLoading = false,
                        errorMessage = "Error ${result.code}: ${result.message}"
                    )
                }
                is NetworkResult.Exception -> {
                    _uiState.value = _uiState.value.copy(
                        isLoading = false,
                        errorMessage = result.throwable.localizedMessage ?: "Unknown error"
                    )
                }
            }
        }
    }

    fun fetchCurrentUser() {
        viewModelScope.launch {
            _uiState.value = _uiState.value.copy(isLoading = true, errorMessage = null)

            when (val result = userRepository.getCurrentUser()) {
                is NetworkResult.Success -> {
                    _uiState.value = _uiState.value.copy(
                        isLoading = false,
                        currentUser = result.data
                    )
                }
                is NetworkResult.Error -> {
                    _uiState.value = _uiState.value.copy(
                        isLoading = false,
                        errorMessage = "Error ${result.code}: ${result.message}"
                    )
                }
                is NetworkResult.Exception -> {
                    _uiState.value = _uiState.value.copy(
                        isLoading = false,
                        errorMessage = result.throwable.localizedMessage ?: "Unknown error"
                    )
                }
            }
        }
    }

    fun setAuthToken(token: String) {
        com.example.network.NetworkClient.getTokenProvider().saveAccessToken(token)
    }

    fun logout() {
        com.example.network.NetworkClient.getTokenProvider().clearTokens()
        _uiState.value = UserUiState()
    }
}